// var leaks out of blocks
function countDown() {
  for (var i = 10; i > 0; i--) {
    // ...
  }
  console.log(i); // 0 — i is still accessible after the loop
}

// Hoisting trap
console.log(x); // undefined (not an error — var is hoisted)
var x = 5;
console.log(x); // 5

// Duplicate declaration silently succeeds
var name = 'Alice';
var name = 'Bob'; // No error in JS; TypeScript raises TS2451 in the same scope

// let is block-scoped
function countDown() {
  for (let i = 10; i > 0; i--) {
    // i is only visible inside this loop body
  }
  // console.log(i); // TS2304: Cannot find name 'i'
}

// Temporal Dead Zone
// console.log(value); // ReferenceError at runtime
let value = 42;

// Re-assignment is fine
let score = 0;
score = 100; // OK

// Re-declaration in the same scope is an error
// let score = 200; // TS2451: Cannot redeclare block-scoped variable 'score'

// const binding cannot be re-assigned
const PI = 3.14159;
// PI = 3; // TS2588: Cannot assign to 'PI' because it is a constant

// Object properties ARE mutable
const user = { name: 'Alice', age: 30 };
user.name = 'Bob'; // OK — the binding stays the same object
// user = { name: 'Bob', age: 30 }; // TS2588 — re-assignment of binding is not allowed

// Arrays are mutable too
const scores: number[] = [10, 20, 30];
scores.push(40); // OK
// scores = []; // TS2588

// const requires an initialiser
// const x; // TS1155: 'const' declarations must be initialized

// Explicit annotations
let username: string = 'alice';
let count: number = 0;
let isActive: boolean = true;
let data: string[] = ['a', 'b', 'c'];
let pair: [string, number] = ['height', 180]; // tuple
let anything: unknown = 42; // safer alternative to any

// Angular component class example
export class UserCardComponent {
  title: string = 'User Profile';
  userId: number = 0;
  isAdmin: boolean = false;
  tags: string[] = [];
}

// TypeScript infers the types below
const message = 'hello';          // inferred: string
const count   = 0;                 // inferred: number
const enabled = true;             // inferred: boolean
const items   = ['a', 'b', 'c'];  // inferred: string[]
const ratio   = 3.14;             // inferred: number

// The inferred type is enforced
// message = 42; // TS2322: Type 'number' is not assignable to type 'string'

// Inference widens when you use let
let score = 100;  // inferred: number (not the literal type 100)
score = 200;       // fine

// Inference narrows for const literals
const MAX = 100;  // inferred: 100 (literal type, because const can't change)

// Array destructuring
const [first, second]: [string, number] = ['Alice', 30];

// Object destructuring with rename and default
const { name: userName = 'Anonymous', role = 'guest' } = getUser();

// Destructuring in function parameters (common in Angular)
function formatUser({ name, age }: { name: string; age: number }): string {
  return `${name} (${age})`;
}

// Rest elements
const [head, ...rest]: number[] = [1, 2, 3, 4];
// head: 1, rest: [2, 3, 4]

// Angular: destructuring observable values
this.userService.getUser(id).subscribe(({ name, email }) => {
  this.displayName = name;
  this.email = email;
});

// readonly on a class property
class AppConfig {
  readonly apiUrl: string;

  constructor(url: string) {
    this.apiUrl = url; // OK — only assignment is in the constructor
  }
}

const config = new AppConfig('https://api.example.com');
// config.apiUrl = 'other'; // TS2540: Cannot assign to 'apiUrl'

// as const — freezes the type to literal types
const COLORS = ['red', 'green', 'blue'] as const;
// type: readonly ["red", "green", "blue"]
// COLORS.push('yellow'); // TS2339: Property 'push' does not exist

// Readonly<T> utility type
type ImmutableUser = Readonly<{ name: string; age: number }>;
const u: ImmutableUser = { name: 'Alice', age: 30 };
// u.name = 'Bob'; // TS2540

import { Component, signal, computed, inject } from '@angular/core';
import { UserService } from './user.service';

@Component({
  selector: 'app-counter',
  template: `<p>Count: {{ count() }} | Double: {{ double() }}</p>`
})
export class CounterComponent {
  // injected service — const binding via inject()
  private readonly userService = inject(UserService);

  // Signals: use const (the signal itself doesn't change, its value does)
  count = signal(0);
  double = computed(() => this.count() * 2);

  // Nullable property — needs explicit type
  selectedUser: string | null = null;

  // Constant — value set once, never re-assigned
  readonly componentId = crypto.randomUUID();

  // Mutable local variable inside a method
  increment(): void {
    let step = 1;           // let — value assigned then used
    const next = this.count() + step;   // const — computed once
    this.count.set(next);
  }
}

// Widening with let
let status = 'pending';        // type: string (widened)
const MODE   = 'dark';         // type: 'dark' (literal — const never changes)

// Narrowing via typeof guard
function process(value: string | number): void {
  if (typeof value === 'string') {
    // TypeScript knows value is string here
    console.log(value.toUpperCase());
  } else {
    // TypeScript knows value is number here
    console.log(value.toFixed(2));
  }
}

// Narrowing via truthiness
let username: string | null = fetchUsername();
if (username) {
  // username is string here (null is falsy)
  console.log(username.trim());
}

// Narrowing via in-operator
function printArea(shape: { kind: 'circle'; radius: number } | { kind: 'rect'; width: number; height: number }) {
  if (shape.kind === 'circle') {
    console.log(Math.PI * shape.radius ** 2);
  } else {
    console.log(shape.width * shape.height);
  }
}

// Type assertion with as
const input = document.getElementById('search') as HTMLInputElement;
input.value = ''; // OK — TypeScript now knows it's an HTMLInputElement

// Non-null assertion (!)
const element = document.querySelector('#root')!; // asserts not null/undefined

// Double assertion — escape hatch (use sparingly)
const value = (someAny as unknown) as string;

// In Angular templates, type assertions are rare — use type guards instead
// In component code:
const el = this.elementRef.nativeElement as HTMLDivElement;

export class ProductComponent {
  // public (default) — accessible from templates and outside the class
  public title: string = 'Widget';

  // protected — accessible in this class and subclasses
  protected basePrice: number = 0;

  // private — accessible only inside this class (compile-time)
  private _internalCache: Map<string, unknown> = new Map();

  // private field (# prefix) — true runtime privacy, ES2022
  #secret: string = 'runtime-private';

  // readonly — set once (constructor or inline)
  readonly id: string = crypto.randomUUID();
}

// Without parameter properties
class UserService {
  private readonly http: HttpClient;

  constructor(http: HttpClient) {
    this.http = http;
  }
}

// With parameter properties (same result, less boilerplate)
class UserService {
  constructor(private readonly http: HttpClient) {}
}

// Angular 14+ inject() is preferred, but parameter properties still appear widely
@Injectable({ providedIn: 'root' })
class DataService {
  constructor(
    private readonly http: HttpClient,
    private readonly logger: LoggerService
  ) {}
}

// With strictNullChecks on (Angular default)
let name: string = null; // TS2322 — must be string | null

let nullable: string | null = null;
nullable = 'Alice'; // OK

// Optional chaining — safe navigation
const city = user?.address?.city; // undefined if any step is null/undefined

// Nullish coalescing — default when null or undefined
const displayName = user.name ?? 'Anonymous';

// Non-null assertion — suppress the null check when you are certain
const el = document.getElementById('root')!;

// Angular async pipe returns null before data arrives
// Template: {{ user$ | async | json }}
// Component type: Observable<User | null> — the | null is explicit

// Use const for the subscription — the subscription object doesn't change
const sub = this.dataService.getData().subscribe(data => {
  // Use const for values you compute once inside the callback
  const processed = data.map(item => ({ ...item, label: item.name.trim() }));
  this.items = processed;
});

// Store in a class property to unsubscribe later
private subscription: Subscription | null = null;

ngOnInit(): void {
  this.subscription = this.route.params.subscribe(params => {
    const id = params['id'];     // const — computed once
    this.loadUser(id);
  });
}

ngOnDestroy(): void {
  this.subscription?.unsubscribe();
}

import { signal, computed, effect } from '@angular/core';

// Signals: always const — you call .set()/.update() on the signal
const count = signal(0);
const doubled = computed(() => count() * 2);

// effect uses const for derived values inside its callback
effect(() => {
  const current = count(); // const — read once per effect run
  console.log(`Count changed to ${current}`);
});

// Signal holding an object — update the object, not the binding
const user = signal<{ name: string; age: number }>({ name: 'Alice', age: 30 });
user.update(u => ({ ...u, age: u.age + 1 })); // immutable update pattern
